import os
from typing import Any, Dict

import modal
from fastapi import Request

os.environ.setdefault("MODAL_ENVIRONMENT", "modal-vsdatagen")

APP_NAME = "rate-limited-api-gateway"
DICT_NAME = "rate-limited-api-gateway-output"
SECRET_NAME = "rate-limited-api-gateway-secret"

app = modal.App(APP_NAME)
rate_limit_dict = modal.Dict.from_name(DICT_NAME, create_if_missing=True)
secret = modal.Secret.from_name(SECRET_NAME)


@app.cls(secrets=[secret])
class RateLimitedGateway:
    @modal.enter()
    def setup(self) -> None:
        self.gateway_api_key = os.environ["GATEWAY_API_KEY"]
        self.rate_limit_max = int(os.environ["RATE_LIMIT_MAX"])
        self._ensure_stats()

    def _ensure_stats(self) -> None:
        defaults = {
            "total_requests_processed": 0,
            "rate_limit_hits": 0,
            "gateway_status": "operational",
            "api_version": "v1",
        }
        for key, value in defaults.items():
            if rate_limit_dict.get(key) is None:
                rate_limit_dict[key] = value

    def _increment(self, key: str, delta: int = 1) -> int:
        current = rate_limit_dict.get(key) or 0
        updated = int(current) + delta
        rate_limit_dict[key] = updated
        return updated

    def _process_core(self, api_key: str | None, payload: Dict[str, Any]) -> Dict[str, Any]:
        self._ensure_stats()
        if not api_key or api_key != self.gateway_api_key:
            return {"status": "error", "detail": "Unauthorized", "code": 401}

        counter_key = f"count:{api_key}"
        current = rate_limit_dict.get(counter_key) or 0
        if int(current) >= self.rate_limit_max:
            self._increment("rate_limit_hits")
            rate_limit_dict["gateway_status"] = "operational"
            rate_limit_dict["api_version"] = "v1"
            return {
                "status": "error",
                "detail": "Rate limit exceeded",
                "code": 429,
                "limit": self.rate_limit_max,
            }

        rate_limit_dict[counter_key] = int(current) + 1
        processed = self._increment("total_requests_processed")
        rate_limit_dict["gateway_status"] = "operational"
        rate_limit_dict["api_version"] = "v1"
        remaining = self.rate_limit_max - int(current) - 1
        return {
            "status": "ok",
            "processed": processed,
            "remaining": remaining,
            "payload": payload,
        }

    @modal.method()
    def process(self, api_key: str, payload: Dict[str, Any]) -> Dict[str, Any]:
        return self._process_core(api_key, payload)

    @modal.web_endpoint(method="POST")
    async def handle(self, request: Request) -> Dict[str, Any]:
        payload = await request.json()
        api_key = request.headers.get("x-api-key") or payload.get("api_key")
        return self._process_core(api_key, payload)


@app.local_entrypoint()
def main() -> None:
    api_key = os.environ.get("GATEWAY_API_KEY", "gateway-key-prod-2024")
    payload = {"message": "hello from local entrypoint"}
    result = RateLimitedGateway().process.remote(api_key, payload)
    print("Gateway response:", result)
